{
    "level": "B1–B2",
    "intro": "In this topic, you will learn how to form the passive with <strong>phrasal verbs</strong>. The main rule: <strong>the preposition or participle remains with the verb</strong>.",
    "rules": [
        {
            "label": "Active",
            "color": "emerald",
            "text": "<strong>Subject + phrasal verb + object</strong>:",
            "example": "They called off the meeting."
        },
        {
            "label": "Passive",
            "color": "blue",
            "text": "<strong>Object + be + V3 + particle/preposition</strong>:",
            "example": "The meeting was called off."
        },
        {
            "label": "Importantly",
            "color": "rose",
            "text": "The participle/preposition is <strong>inseparable</strong> from the verb:",
            "example": "The baby was looked after. ✅ (не: was looked the baby after ❌)"
        }
    ]
}

{
    "title": "1. Typical phrasal verbs in the passive",
    "intro": "The most common phrasal verbs used in the passive:",
    "items": [
        {
            "label": "look after",
            "title": "care",
            "subtitle": "The children are looked after well."
        },
        {
            "label": "bring up",
            "title": "educate",
            "subtitle": "She was brought up by her grandmother."
        },
        {
            "label": "call off",
            "title": "cancel",
            "subtitle": "The match was called off."
        },
        {
            "label": "put off",
            "title": "postpone",
            "subtitle": "The meeting was put off until Monday."
        },
        {
            "label": "turn down",
            "title": "reject",
            "subtitle": "His offer was turned down."
        },
        {
            "label": "carry out",
            "title": "perform",
            "subtitle": "The experiment was carried out."
        },
        {
            "label": "look into",
            "title": "investigate",
            "subtitle": "The matter is being looked into."
        },
        {
            "label": "break into",
            "title": "break in",
            "subtitle": "The house was broken into."
        }
    ]
}

{
    "title": "2. Comparison of Active vs Passive",
    "intro": "Transformation of phrasal verbs from active to passive:",
    "rows": [
        {
            "en": "Active: They called off the game.",
            "ua": "Active: They called off the game.",
            "note": "→ Passive: The game was called off."
        },
        {
            "en": "Active: Someone broke into the car.",
            "ua": "Active: Someone broke into the car.",
            "note": "→ Passive: The car was broken into."
        },
        {
            "en": "Active: They are looking into the problem.",
            "ua": "Active: They are looking into the problem.",
            "note": "→ Passive: The problem is being looked into."
        },
        {
            "en": "Active: Her grandparents brought her up.",
            "ua": "Active: Her grandparents brought her up.",
            "note": "→ Passive: She was brought up by her grandparents."
        }
    ],
    "warning": "📌 The participle/preposition ALWAYS remains with the verb!"
}

{
    "title": "3. Phrasal verbs in the passive by categories",
    "sections": [
        {
            "label": "Cancellation / postponement",
            "color": "rose",
            "description": "call off, put off, cancel:",
            "examples": [
                {
                    "en": "The concert was called off due to rain.",
                    "ua": "The concert was called off due to rain."
                },
                {
                    "en": "The meeting has been put off.",
                    "ua": "The meeting has been put off."
                },
                {
                    "en": "The flight was put off until tomorrow.",
                    "ua": "The flight was put off until tomorrow."
                }
            ]
        },
        {
            "label": "Implementation / implementation",
            "color": "emerald",
            "description": "carry out, bring about, set up:",
            "examples": [
                {
                    "en": "The research was carried out last year.",
                    "ua": "The research was carried out last year."
                },
                {
                    "en": "Major changes were brought about.",
                    "ua": "Major changes were brought about."
                },
                {
                    "en": "A new company was set up.",
                    "ua": "A new company was set up."
                }
            ]
        },
        {
            "label": "Rejection / refusal",
            "color": "blue",
            "description": "turn down, rule out, throw out:",
            "examples": [
                {
                    "en": "Her application was turned down.",
                    "ua": "Her application was turned down."
                },
                {
                    "en": "This option cannot be ruled out.",
                    "ua": "This option cannot be ruled out."
                },
                {
                    "en": "The proposal was thrown out.",
                    "ua": "The proposal was thrown out."
                }
            ]
        },
        {
            "label": "Care / upbringing",
            "color": "amber",
            "description": "look after, bring up, take care of:",
            "examples": [
                {
                    "en": "The patient is being looked after.",
                    "ua": "The patient is being looked after."
                },
                {
                    "en": "He was brought up in a small village.",
                    "ua": "He was brought up in a small village."
                },
                {
                    "en": "Everything will be taken care of.",
                    "ua": "Everything will be taken care of."
                }
            ]
        }
    ]
}

{
    "title": "4. Phrasal verbs in the passive: different tenses",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "<strong>am/is/are + V3 + particle</strong>:",
            "examples": [
                {
                    "en": "Children are looked after at the nursery.",
                    "ua": "Children are looked after at the nursery."
                },
                {
                    "en": "Problems are dealt with quickly.",
                    "ua": "Problems are dealt with quickly."
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "blue",
            "description": "<strong>was/were + V3 + particle</strong>:",
            "examples": [
                {
                    "en": "The project was carried out successfully.",
                    "ua": "The project was carried out successfully."
                },
                {
                    "en": "The meeting was called off yesterday.",
                    "ua": "The meeting was called off yesterday."
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "<strong>has/have been + V3 + particle</strong>:",
            "examples": [
                {
                    "en": "The event has been put off.",
                    "ua": "The event has been put off."
                },
                {
                    "en": "His idea has been turned down.",
                    "ua": "His idea has been turned down."
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "rose",
            "description": "<strong>am/is/are being + V3 + particle</strong>:",
            "examples": [
                {
                    "en": "The matter is being looked into.",
                    "ua": "The matter is being looked into."
                },
                {
                    "en": "New measures are being brought in.",
                    "ua": "New measures are being brought in."
                }
            ]
        }
    ]
}

{
    "title": "5. Verbs with prepositions in the passive",
    "intro": "Verbs with fixed prepositions also form the passive:",
    "items": [
        {
            "label": "laugh at",
            "title": "laugh with",
            "subtitle": "He hates being laughed at."
        },
        {
            "label": "look at",
            "title": "look at",
            "subtitle": "The painting is being looked at."
        },
        {
            "label": "speak to",
            "title": "talk to",
            "subtitle": "I don't like being spoken to like that."
        },
        {
            "label": "refer to",
            "title": "refer to",
            "subtitle": "This book is often referred to."
        },
        {
            "label": "rely on",
            "title": "rely on",
            "subtitle": "He can be relied on."
        },
        {
            "label": "deal with",
            "title": "to deal with",
            "subtitle": "The problem is being dealt with."
        }
    ]
}

{
    "title": "6. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Detachment of the participle from the verb.",
            "wrong": "The baby was looked well after.",
            "right": "✅ The baby was looked after well."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Omission of participle/preposition.",
            "wrong": "The meeting was called.",
            "right": "✅ The meeting was called off."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Incorrect preposition.",
            "wrong": "He was laughed on by everyone.",
            "right": "✅ He was laughed at by everyone."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Incorrect word order with by.",
            "wrong": "The child was by her aunt brought up.",
            "right": "✅ The child was brought up by her aunt."
        }
    ]
}
